#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char chairs[N + 1];
        scanf("%s", chairs);
        int children = 0;
        for (int i = 0; i < N; i++) {
            if (chairs[i] == '1') children++;
        }
        int max_empty = 0;
        int current_empty = 0;
        for (int i = 0; i < N; i++) {
            if (chairs[i] == '0') current_empty++;
            else {
                max_empty = (max_empty > current_empty) ? max_empty : current_empty;
                current_empty = 0;
            }
        }
        max_empty = (max_empty > current_empty) ? max_empty : current_empty;
        printf("%d\n", children - (max_empty >= children ? children : max_empty));
    }
    return 0;
}

