import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            String chairs = scanner.next();
            int children = 0;
            for (int i = 0; i < N; i++) {
                if (chairs.charAt(i) == '1') children++;
            }
            int max_empty = 0;
            int current_empty = 0;
            for (int i = 0; i < N; i++) {
                if (chairs.charAt(i) == '0') current_empty++;
                else {
                    max_empty = (max_empty > current_empty) ? max_empty : current_empty;
                    current_empty = 0;
                }
            }
            max_empty = (max_empty > current_empty) ? max_empty : current_empty;
            System.out.println(children - (max_empty >= children ? children : max_empty));
        }
    }
}

